module johnson_counter (
    input clk,
    input reset,
    output [4:0] q );reg [4:0] invalid_count;

always @(posedge clk) begin
    if (reset)
        invalid_count <= 5'b00000;
    else
        invalid_count <= {invalid_count[3:0], ~invalid_count[4]};
end

assign q = invalid_count;

endmodule
